(414,	0,	30,	20251009,	'reply',	'Okay, here\'s a one-sentence summary of the University of New South Wales (UNSW):\n\nUNSW is a globally recognised, research-intensive university based in Sydney, Australia, renowned for its strong programs in engineering, technology, science, and business, and a focus on practical application and industry engagement.',	'immigration',	1,	0,	'2025-10-09 01:19:45',	0,	'2025-10-09 01:19:45',	0,	NULL),
