INSERT INTO `app_event` (`uid`, `parent_id`, `id`, `target_date`, `target_country`, `title`, `content`, `meta_title`, `meta_description`, `meta_image`, `utoken`, `disabled`, `level`, `lang`, `seq`, `status`, `created_by`, `created_at`, `updated_by`, `updated_at`, `deleted_by`, `deleted_at`) VALUES
(1,	0,	1,	'2022-06-12',	1,	'The 3rd Immigration Exhibition',	'&lt;p&gt;At the 3rd Immigration Exhibition held at the Wanchai Convention and Exhibition in Hong Kong on June 11 and 12, 2022, Wealthskey cooperated with Vision Overseas Consultants to promote a one-stop service from immigration to property search.&lt;/p&gt;',	'',	'',	'',	'6858c78fba2f77e4aef8b81a57b74dac',	0,	1,	1,	1,	1,	1,	'2024-04-02 16:58:45',	1,	'2024-04-09 17:34:27',	0,	NULL),
(2,	0,	1,	'2022-06-12',	1,	'第三屆移民展',	'&lt;p&gt;2022年6月11和12日在香港灣仔會展舉辦的第三届移民展Wealthskey與願景海外顧問合作推介由移民到搵樓一條龍服務。&lt;/p&gt;',	'',	'',	'',	'6858c78fba2f77e4aef8b81a57b74dac',	0,	1,	2,	1,	1,	1,	'2024-04-02 16:58:45',	1,	'2024-04-09 17:34:27',	0,	NULL),
(3,	0,	1,	'2022-06-12',	1,	'第三届移民展',	'&lt;p&gt;2022年6月11和12日在香港湾仔会展举办的第三届移民展Wealthskey与愿景海外顾问合作推介由移民到搵楼一条龙服务。&lt;/p&gt;',	'',	'',	'',	'6858c78fba2f77e4aef8b81a57b74dac',	0,	1,	3,	1,	1,	1,	'2024-04-02 16:58:45',	1,	'2024-04-09 17:34:27',	0,	NULL),
(4,	0,	2,	'2023-11-05',	1,	'The 22nd Shanghai Immigration and Study Abroad Exhibition',	'&lt;p&gt;Wealthskey will participate in the 22nd Shanghai Overseas Real Estate Immigration Study Abroad Expo in Shanghai on November 5-6, 2023, and hold two on-site lectures. Our US Eb2 NIW direct green card visa, Canadian SUV permanent residence visa and Irish work visa projects are all very popular.&lt;/p&gt;',	'',	'',	'',	'e4fcb3c4102b17bb4405bcb0a75a5695',	0,	1,	1,	2,	1,	1,	'2024-04-02 17:02:33',	1,	'2024-04-09 17:34:21',	0,	NULL),
(5,	0,	2,	'2023-11-05',	1,	'第22届上海移民留學展',	'&lt;p&gt;Wealthskey在2023年11月5-6日在上海參𠩐第二十二屆上海海外置業移民留學𠩐覽會，並舉辦兩場現場講座。我們的美國Eb2 NIW 直接綠卡簽證、加拿大SUV永居簽證及愛爾蘭工簽項目均大受歡迎。&lt;/p&gt;',	'',	'',	'',	'e4fcb3c4102b17bb4405bcb0a75a5695',	0,	1,	2,	2,	1,	1,	'2024-04-02 17:02:33',	1,	'2024-04-09 17:34:21',	0,	NULL),
(6,	0,	2,	'2023-11-05',	1,	'第22届上海移民留学展',	'&lt;p&gt;Wealthskey在2023年11月5-6日在上海参𠩐第二十二届上海海外置业移民留学𠩐览会，并举办两场现场讲座。我们的美国Eb2 NIW 直接绿卡签证、加拿大SUV永居签证及爱尔兰工签项目均大受欢迎。&lt;/p&gt;',	'',	'',	'',	'e4fcb3c4102b17bb4405bcb0a75a5695',	0,	1,	3,	2,	1,	1,	'2024-04-02 17:02:33',	1,	'2024-04-09 17:34:21',	0,	NULL);
INSERT INTO `app_faq` (`uid`, `parent_id`, `id`, `title`, `content`, `meta_title`, `meta_description`, `meta_image`, `utoken`, `disabled`, `level`, `lang`, `seq`, `status`, `created_by`, `created_at`, `updated_by`, `updated_at`, `deleted_by`, `deleted_at`) VALUES
(1,	0,	1,	'What is AI-mmi?',	'&lt;p&gt;AI-mmi is an artificial intelligent migration consultant and a one-stop-shop migration platform. AI-mmi not only answers questions related to migration matters, but also assists your visa submission by assessing your eligibility, filling out the required forms (limited services at this stage) and validating your documents and application.&lt;/p&gt;',	NULL,	NULL,	NULL,	'fddc2104e49a13fa00227299f3e8de10',	0,	1,	1,	4,	1,	1,	'2024-01-12 14:24:35',	1,	'2024-07-23 15:44:40',	0,	NULL),
(2,	0,	2,	'How does it work?',	'&lt;p&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;&lt;strong&gt;Free Assessment&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;\r\n&lt;p&gt;If you are not sure where to start, you may either&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;take a free assessment here (AI assisted), or&lt;/li&gt;\r\n&lt;li&gt;contact one of our migration agents here, they will follow up with you for an obligation-free assessment (non AI).&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;Consultation&lt;/span&gt;&lt;/strong&gt;&lt;br /&gt;You may also&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;ask up to 3 questions for free to AI-mmi. If you need to get help from AI-mmi beyond that, consider our Premium AI services, or&lt;/li&gt;\r\n&lt;li&gt;contact one of our migration agents here for a paid consultation. (non AI)&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;&lt;strong&gt;Visa Application&lt;/strong&gt;&lt;/span&gt;&lt;br /&gt;You may start your migration plan, and a visa application by either:&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;DIY (do it yourself) with the support of AI-mmi, including but not limited to visa advisory, application form filling (limited forms at this stage), and document and application validation, or&lt;/li&gt;\r\n&lt;li&gt;engage one of our migration agents here for a professional visa service.&lt;/li&gt;\r\n&lt;/ul&gt;',	NULL,	NULL,	NULL,	'2cb930e7c4ccf433598ccfb126aef4e6',	0,	1,	1,	3,	1,	1,	'2024-01-12 14:29:42',	1,	'2024-07-23 15:44:40',	0,	NULL),
(3,	0,	3,	'Why shall I pay to get answers from AI-mmi while I can get those for free from other AI chat bots like ChatGPT?',	'&lt;p&gt;AI-mmi is specially trained on migration fields so she is more reliable and more capable in this area than other AI tools, and an alternative to migration agents. While you may get answers from other AI chat bots for free, it could be much more costly to you in a lifetime if you are not getting the most accurate and up dated information. Migration is a life impacting decision and you shall be relying on specially trained and subject matter experts in this field.&lt;/p&gt;',	NULL,	NULL,	NULL,	'730d0fd3a8fd5d7818e242b21996ae8c',	0,	1,	1,	2,	1,	1,	'2024-01-12 14:33:56',	1,	'2024-07-23 15:44:40',	0,	NULL),
(4,	0,	4,	'Shall I still hire a real migration agent if I can access to AI here?',	'&lt;p&gt;We also acknowledge that AI may not and shall not completely replace human, therefore our AI-mmi platform continues to offer choices of working with professional migration agents or lawyers as a conventional option.&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;The benefits of working with an agent here (not AI):&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;If they are registered and licensed in the country they served, you will have a chance to file a complaint if you are not satisfied with their services (that you can&amp;rsquo;t do this on AI);&lt;/li&gt;\r\n&lt;li&gt;If your visa is not successful, the registered migration agent may file an appeal on your behalf for a review (that AI is unable to do this);&lt;/li&gt;\r\n&lt;li&gt;If your situation is complex, a professional agent may go through your case in more details and provide you with personal advice beyond the paper work and emotional support that AI is unable to offer;&lt;/li&gt;\r\n&lt;li&gt;If you just want to be completely hands-free, without the hassles of doing all the paper work and going through the process, you should hire a professional human to do all the works for you. There are still quite a sizeable amount of work you have to complete even with the help of AI;&lt;/li&gt;\r\n&lt;li&gt;If you are not less comfortable with online tasks, forms, professional English writing (especially writing your profile or visa related statements), and finding it hard to understand some of the policy and legal languages, working with a human being could be a better option.&lt;/li&gt;\r\n&lt;/ul&gt;',	NULL,	NULL,	NULL,	'4cead26b122d02ff431b6a1f13b2c46c',	0,	1,	1,	1,	1,	1,	'2024-01-12 14:35:25',	1,	'2024-07-23 15:44:40',	0,	NULL),
(5,	0,	1,	'AI-mmi是什麼？',	'&lt;p&gt;AI-mmi是人工智能移民顧問和一站式移民平台。 AI-mmi不僅回答與移民事宜相關的問題，還透過評估您的資格、自動填寫所需表格（現階段衹提供有限度服務）以及驗證您的文件和資料來協助您的移民申請。&lt;/p&gt;',	NULL,	NULL,	NULL,	'fddc2104e49a13fa00227299f3e8de10',	0,	1,	2,	4,	1,	1,	'2024-02-05 10:54:07',	1,	'2024-07-23 15:44:40',	0,	NULL),
(6,	0,	1,	'AI-mmi是什么？',	'&lt;p&gt;AI-mmi是人工智能移民顾问和一站式移民平台。 AI-mmi不仅回答与移民事宜相关的问题，还透过评估您的资格、填写所需表格（现阶段只提供有限度服务）以及验证您的文件和资料来协助您的移民申请。&lt;/p&gt;',	NULL,	NULL,	NULL,	'fddc2104e49a13fa00227299f3e8de10',	0,	1,	3,	4,	1,	1,	'2024-02-05 10:54:07',	1,	'2024-07-23 15:44:40',	0,	NULL),
(7,	0,	2,	'它是如何運作的？',	'&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;&lt;strong&gt;免費評估&lt;/strong&gt;&lt;/span&gt; &lt;/span&gt;&lt;/p&gt;\r\n&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;如果您不確定從哪裡開始，您可以: &lt;/span&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li class=&quot;tw-data-text tw-text-large tw-ta&quot; dir=&quot;ltr&quot; data-placeholder=&quot;Translation&quot; aria-label=&quot;Translated text&quot; data-ved=&quot;2ahUKEwj_1frZvs2GAxUmb2wGHfGxBC4Q3ewLegQIBRAU&quot;&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;先進行免費評估（由人工智能輔助），或 &lt;/span&gt;&lt;/li&gt;\r\n&lt;li class=&quot;tw-data-text tw-text-large tw-ta&quot; dir=&quot;ltr&quot; data-placeholder=&quot;Translation&quot; aria-label=&quot;Translated text&quot; data-ved=&quot;2ahUKEwj_1frZvs2GAxUmb2wGHfGxBC4Q3ewLegQIBRAU&quot;&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;聯絡在我們平台登記的其中一家移民顧問公司，他們將與您聯繫進行免費評估（非 AI）&lt;/span&gt;&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;&lt;strong&gt;諮詢&lt;/strong&gt;&lt;/span&gt; &lt;/span&gt;&lt;/p&gt;\r\n&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;您也可以: &lt;/span&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;向 AI-mmi 免費詢問最多 3 個問題。如果您需要從 AI-mmi 獲得更多協助，請考慮我們的付費 AI 服務，或 &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;聯絡在我們登記的其中一家移民顧問公司進行諮詢（非人工智能）&lt;/span&gt;&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;&lt;strong&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;簽證申請 &lt;/span&gt;&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;\r\n&lt;p&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;您可以透過以下任一方式開始您的移民計劃和簽證申請： &lt;/span&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;在 AI-mmi 的支持下進行 DIY（自己動手），包括但不限於簽證諮詢、申請表填寫（現階段只提供有限服務）以及文件和資料驗證，或 &lt;/span&gt;&lt;/li&gt;\r\n&lt;li&gt;&lt;span class=&quot;Y2IQFc&quot; lang=&quot;zh-TW&quot;&gt;聘請我們的移民顧問之一來提供專業的移民服務&lt;/span&gt;&lt;/li&gt;\r\n&lt;/ul&gt;',	NULL,	NULL,	NULL,	'2cb930e7c4ccf433598ccfb126aef4e6',	0,	1,	2,	3,	1,	1,	'2024-02-05 11:03:33',	1,	'2024-07-23 15:44:40',	0,	NULL),
(8,	0,	2,	'它是如何运作的？',	'&lt;p&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;&lt;strong&gt;免费评估&lt;/strong&gt;&lt;/span&gt;&lt;/p&gt;\r\n&lt;p&gt;如果您不确定从哪里开始，您可以&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;先进行免费评估（由人工智能辅助），或&lt;/li&gt;\r\n&lt;li&gt;联络在我们平台登记的其中一家移民顾问公司，他们将与您联系进行免费评估（非 AI）&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;咨询&lt;/span&gt;&lt;/strong&gt;&lt;br /&gt;您也可以&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;向 AI-mmi 免费询问最多 3 个问题。 如果您需要从 AI-mmi 获得更多协助，请考虑我们的付费 AI 服务，或&lt;/li&gt;\r\n&lt;li&gt;联络在我们登记的其中一家移民顾问公司进行咨询（非人工智能）&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;span style=&quot;text-decoration: underline;&quot;&gt;&lt;strong&gt;签证申请&lt;/strong&gt;&lt;/span&gt;&lt;br /&gt;您可以透过以下任一方式开始您的移民计划和签证申请：&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;在 AI-mmi 的支持下进行 DIY（自己动手），包括但不限于签证咨询、申请表填写（现阶段只提供有限服务）以及文件和资料验证，或&lt;/li&gt;\r\n&lt;li&gt;聘请我们的其中一位移民顾问来提供专业的移民服务&lt;/li&gt;\r\n&lt;/ul&gt;',	NULL,	NULL,	NULL,	'2cb930e7c4ccf433598ccfb126aef4e6',	0,	1,	3,	3,	1,	1,	'2024-02-05 11:03:33',	1,	'2024-07-23 15:44:40',	0,	NULL),
(9,	0,	3,	'為什麼我要付費從 AI-mmi 獲得答案，在 ChatGPT 等其他 AI 工具都是免費？',	'&lt;p&gt;AI-mmi經過專門針對移民領域的培訓，因此她在這方面比其他人工智能工具更可靠、資料更準確。 雖然您可以免費從其他人工智能聊天機器人那裡獲得答案，但如果資料不夠準確或不是最新的信息，可能您會而付出更大的代價。 移民是一個影響一生的決定，建議使用在該領域經過專門訓練的AI專家或專業人士。&lt;/p&gt;',	NULL,	NULL,	NULL,	'730d0fd3a8fd5d7818e242b21996ae8c',	0,	1,	2,	2,	1,	1,	'2024-02-05 11:04:05',	1,	'2024-07-23 15:44:40',	0,	NULL),
(10,	0,	3,	'为什么我要付费从 AI-mmi 获得答案，在 ChatGPT 等其他 AI 工具都是免费？',	'&lt;p&gt;AI-mmi经过专门针对移民领域的培训，因此她在这方面比其他人工智能工具更可靠、资料更准确。 虽然您可以免费从其他人工智能聊天机器人那里获得答案，但如果资料不够准确或不是最新的信息，可能您会而付出更大的代价。 移民是一个影响一生的决定，建议使用在该领域经过专门训练的AI专家或专业人士。&lt;/p&gt;',	NULL,	NULL,	NULL,	'730d0fd3a8fd5d7818e242b21996ae8c',	0,	1,	3,	2,	1,	1,	'2024-02-05 11:04:05',	1,	'2024-07-23 15:44:40',	0,	NULL),
(11,	0,	4,	'如果我在這裡能使用人工智能，我還需要聘請真正的移民代理嗎？',	'&lt;p&gt;我們也承認人工智能可能不會也不會完全取代人類，因此我們的AI-mmi平台繼續提供專業移民顧問作為其他選擇。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;使用專業移民顧問的好處是（非人工智能）：&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;要是他們是官方認可之註冊移民顧問，如果您對他們的服務不滿意，您將有權提出投訴（您無法在 AI 上執行此操作）；&lt;/li&gt;\r\n&lt;li&gt;如果您的簽證不成功，註冊移民顧問可以代表您提出上訴以進行重新審核（AI 無法做到）；&lt;/li&gt;\r\n&lt;li&gt;如果您的情況比較複雜，專業顧問可更詳細地處理您的個案，並為您提供 AI 無法做到的文書工作外之情感支持；&lt;/li&gt;\r\n&lt;li&gt;如果您不想花時間和精力，不想做太多文書工作，那麼您應該聘請專業人士來協助您的移民申請。 即使有了人工智能的幫助，您仍然需要完成相當多的文書及申請手續；&lt;/li&gt;\r\n&lt;li&gt;如果您對線上申請、填寫表格、專業文案寫作（尤其是撰寫您的個人資料或簽證要求之相關文件）不太在行，並且發現難以理解某些移民政策和法律語言，那麼找專業移民顧問可能是更好的選擇。&lt;/li&gt;\r\n&lt;/ul&gt;',	NULL,	NULL,	NULL,	'4cead26b122d02ff431b6a1f13b2c46c',	0,	1,	2,	1,	1,	1,	'2024-02-05 11:04:55',	1,	'2024-07-23 15:44:40',	0,	NULL),
(12,	0,	4,	'如果我在这里能使用人工智能，我还需要聘请真正的移民代理吗？',	'&lt;p&gt;我们也承认人工智能可能不会也不会完全取代人类，因此我们的AI-mmi平台继续提供专业移民顾问作为其他选择。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;使用专业移民顾问的好处是（非人工智能）：&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;要是他们是官方认可之註册移民顾问，如果您对他们的服务不满意，您将有权提出投诉（您无法在 AI 上执行此操作）；&lt;/li&gt;\r\n&lt;li&gt;如果您的签证不成功，註册移民顾问可以代表您提出上诉以进行重新审核（AI 无法做到）；&lt;/li&gt;\r\n&lt;li&gt;如果您的情况比较复杂，专业顾问可更详细地处理您的个案，并为您提供 AI 无法做到的文书工作外之情感支持；&lt;/li&gt;\r\n&lt;li&gt;如果您不想花时间和精力，不想做太多文书工作，那么您应该聘请专业人士来协助您的移民申请。 即使有了人工智能的帮助，您仍然需要完成相当多的文书及申请手续；&lt;/li&gt;\r\n&lt;li&gt;如果您对线上申请、填写表格、专业文案写作（尤其是撰写您的个人资料或签证要求之相关文件）不太在行，并且发现难以理解某些移民政策和法律语言，那么找专业移民顾问可能是更好的选择。&lt;/li&gt;\r\n&lt;/ul&gt;',	NULL,	NULL,	NULL,	'4cead26b122d02ff431b6a1f13b2c46c',	0,	1,	3,	1,	1,	1,	'2024-02-05 11:04:55',	1,	'2024-07-23 15:44:40',	0,	NULL);
INSERT INTO `app_forum` (`id`, `member_id`, `forum_country`, `forum_topic`, `forum_content`, `last_comment_by`, `last_comment_at`, `total_view`, `status`, `created_by`, `created_at`, `updated_by`, `updated_at`, `deleted_by`, `deleted_at`) VALUES
(1,	2,	3,	'我想移民到加拿大!!!',	'我想移民到加拿大，但我不確定我是否符合資格。我應該從何開始？',	1,	'2024-04-11 12:00:56',	74,	0,	0,	'2024-04-11 11:56:29',	0,	'2024-06-05 20:22:22',	1,	'2024-06-05 20:23:07'),
(2,	3,	4,	'有什麼移民計劃適合我？',	'我是一名技術工作者，想移民到澳大利亞工作。有什麼移民計劃適合我？',	2,	'2024-04-11 16:39:46',	893,	1,	0,	'2024-04-11 11:59:56',	0,	'2025-08-06 03:48:59',	0,	NULL),
(3,	7,	3,	'我沒有讀書. 可以移民加拿大?',	'我沒有讀書. 可以移民加拿大?',	7,	'2024-07-08 09:34:29',	764,	1,	0,	'2024-07-08 09:34:29',	0,	'2025-08-05 13:47:09',	0,	NULL);
INSERT INTO `app_forum_comment` (`id`, `member_id`, `forum_id`, `content`, `last_comment_by`, `last_comment_at`, `status`, `created_by`, `created_at`, `updated_by`, `updated_at`, `deleted_by`, `deleted_at`) VALUES
(1,	1,	1,	'如果您想移民到加拿大，首先您應該確定您希望申請的移民類型，例如技術移民、家庭團聚移民或投資移民。每種類型都有不同的資格要求和申請程序。您可以訪問加拿大移民、難民和公民部門（IRCC）的官方網站，了解更多信息，包括不同移民類型的資格要求、申請程序和相關文件。另外，您也可以考慮諮詢專業移民顧問，他們可以幫助您確定最適合您情況的移民途徑，並協助您完成申請程序。',	1,	'2024-04-11 12:00:56',	0,	0,	'2024-04-11 12:00:56',	0,	'2024-04-11 12:00:56',	1,	'2024-06-05 20:23:07'),
(2,	2,	2,	'有冇計過分? 年齡過唔過45?',	2,	'2024-04-11 16:39:46',	1,	0,	'2024-04-11 16:39:46',	0,	'2024-04-11 16:39:46',	0,	NULL);
INSERT INTO `app_free_assessment` (`id`, `member_id`, `questions`, `answers`, `full_name`, `email`, `telephone_code`, `telephone_num`, `status`, `created_by`, `created_at`, `updated_by`, `updated_at`, `deleted_by`, `deleted_at`) VALUES
(1,	0,	'{\"1\":{\"title\":\"Would you like AI-mmi to assess your eligibility for a particular visa and give you an assessment?\",\"answers\":{\"1\":\"Yes\",\"2\":\"No\"}},\"2\":{\"title\":\"Which country you like to move?\",\"answers\":{\"1\":\"Britain\",\"2\":\"United States\",\"3\":\"Canada\",\"4\":\"Australia\"}},\"3\":{\"title\":\"What types of visa you would like to explore?\",\"answers\":{\"1\":\"Skilled immigrant visas\",\"2\":\"Start Up Visa\",\"3\":\"Student visa\",\"4\":\"Family visas\",\"5\":\"Employer sponsorship visas\"}},\"4\":{\"title\":\"What is your education level?\",\"answers\":{\"1\":\"Secondary\",\"2\":\"Diploma or Associate Degreee\",\"3\":\"Bachelor\",\"4\":\"Master\",\"5\":\"Doctoral\"},\"remark\":\"If below Bachelor degree, not qualified for skilled visas\"},\"5\":{\"title\":\"What is your age?\",\"answers\":{\"1\":\"18-25\",\"2\":\"25-33\",\"3\":\"33-40\",\"4\":\"40-45\",\"5\":\"45-55\",\"6\":\"&gt;55\"},\"remark\":\"If over 45, not qulaified for Australia skilled visas\"},\"6\":{\"title\":\"Have you completed an English test?\",\"answers\":{\"1\":\"Yes\",\"2\":\"No\"},\"remark\":\"If answer is No, state that you need to sit for English test before submitting an application.\"},\"7\":{\"title\":\"If yes, what are the test results?\",\"answers\":{\"1\":\"IELTS 6 overall\",\"2\":\"IELTS 6\",\"3\":\"IELTS 7\",\"4\":\"IELTS 8\",\"5\":\"Don\\u2019t have IELTS results yet\"}},\"8\":{\"title\":\"What is your occupation?\",\"answers\":\"\"},\"9\":{\"title\":\"How many years full time work experience you got?\",\"answers\":{\"1\":\"&gt; 1 year\",\"2\":\"1-3 years\",\"3\":\"3-5 years\",\"4\":\"5-8 year\",\"5\":\"&gt; 8 years\"},\"remark\":\"If below 3 years, not qualified for skilled visas\"},\"10\":{\"title\":\"How many years full time work you gained in the country that you are planning to move?\",\"answers\":{\"1\":\"0 year\",\"2\":\"1-3 years\",\"3\":\"3-5 years\",\"4\":\"5-8 year\",\"5\":\"&gt; 8 years\"}},\"11\":{\"title\":\"Do you have a job offer from the target country?\",\"answers\":{\"1\":\"Yes\",\"2\":\"No\"},\"remark\":\"If yes, qualified for skilled and employer sponsor visas\"}}',	'{\"1\":\"1\",\"2\":\"2\",\"3\":\"4\",\"4\":\"4\",\"5\":\"2\",\"6\":\"1\",\"7\":\"3\",\"8\":\"xxx\",\"9\":\"4\",\"10\":\"4\",\"11\":\"1\"}',	'Ken Poon',	'ken@at-creative.com',	'852',	'12345678',	1,	0,	'2024-04-10 19:21:05',	0,	'2024-04-10 19:21:05',	0,	NULL),
