ffer from the target country?\",\"answers\":{\"1\":\"Yes\",\"2\":\"No\"},\"remark\":\"If yes, qualified for skilled and employer sponsor visas\"}}',	'{\"1\":\"1\",\"2\":\"2\",\"3\":\"2\",\"4\":\"4\",\"5\":\"4\",\"6\":\"2\",\"7\":\"5\",\"8\":\"Accountant\",\"9\":\"2\",\"10\":\"4\",\"11\":\"2\"}',	'kp',	'kenith_p@yahoo.com',	'852',	'98684187',	1,	0,	'2024-04-10 23:28:41',	0,	'2024-04-10 23:28:41',	0,	NULL),
