ffer from the target country?\",\"answers\":{\"1\":\"Yes\",\"2\":\"No\"},\"remark\":\"If yes, qualified for skilled and employer sponsor visas\"}}',	'{\"1\":\"1\",\"2\":\"2\",\"3\":\"2\",\"4\":\"2\",\"5\":\"6\",\"6\":\"2\",\"7\":\"4\",\"8\":\"hhh\",\"9\":\"3\",\"10\":\"4\",\"11\":\"2\"}',	'Ken Poon',	'ken@wealthskey.com',	'852',	'12345648',	1,	0,	'2024-04-16 15:20:26',	0,	'2024-04-16 15:20:26',	0,	NULL),
(4,	0,	'{\"1\":{\"title\":\"Would you like AI-mmi to assess your eligibility for a particular visa and give you an assessment?\",\"answers\":{\"1\":\"Yes\",\"2\":\"No\"}},\"2\":{\"title\":\"Which country you like to move?\",\"answers\":{\"1\":\"Britain\",\"2\":\"United States\",\"3\":\"Canada\",\"4\":\"Australia\"}},\"3\":{\"title\":\"What types of visa you would like to explore?\",\"answers\":{\"1\":\"Skilled immigrant visas\",\"2\":\"Start Up Visa\",\"3\":\"Student visa\",\"4\":\"Family visas\",\"5\":\"Employer sponsorship visas\"}},\"4\":{\"title\":\"What is your education level?\",\"answers\":{\"1\":\"Secondary\",\"2\":\"Diploma or Associate Degreee\",\"3\":\"Bachelor\",\"4\":\"Master\",\"5\":\"Doctoral\"},\"remark\":\"If below Bachelor degree, not qualified for skilled visas\"},\"5\":{\"title\":\"What is your age?\",\"answers\":{\"1\":\"18-25\",\"2\":\"25-33\",\"3\":\"33-40\",\"4\":\"40-45\",\"5\":\"45-55\",\"6\":\"&gt;55\"},\"remark\":\"If over 45, not qulaified for Australia skilled visas\"},\"6\":{\"title\":\"Have you completed an English test?\",\"answers\":{\"1\":\"Yes\",\"2\":\"No\"},\"remark\":\"If answer is No, state that you need to sit for English test before submitting an application.\"},\"7\":{\"title\":\"If yes, what are the test results?\",\"answers\":{\"1\":\"IELTS 6 overall\",\"2\":\"IELTS 6\",\"3\":\"IELTS 7\",\"4\":\"IELTS 8\",\"5\":\"Don\\u2019t have IELTS results yet\"}},\"8\":{\"title\":\"What is your occupation?\",\"answers\":\"\"},\"9\":{\"title\":\"How many years full time work experience you got?\",\"answers\":{\"1\":\"&gt; 1 year\",\"2\":\"1-3 years\",\"3\":\"3-5 years\",\"4\":\"5-8 year\",\"5\":\"&gt; 8 years\"},\"remark\":\"If below 3 years, not qualified for skilled visas\"},\"10\":{\"title\":\"How many years full time work you gained in the country that you are planning to move?\",\"answers\":{\"1\":\"0 year\",\"2\":\"1-3 years\",\"3\":\"3-5 years\",\"4\":\"5-8 year\",\"5\":\"&gt; 8 years\"}},\"11\":{\"title\":\"Do you have a job o