INSERT INTO `app_member_posts` (`id`, `member_id`, `category_type`, `category_lang`, `category_country`, `title`, `content`, `photo`, `youtube_url`, `highlight`, `status`, `created_by`, `created_at`, `updated_by`, `updated_at`, `deleted_by`, `deleted_at`) VALUES
(1,	1,	1,	2,	3,	'加拿大創業移民',	'仍然未決定到幾時移民? 想搵多幾年錢先走? 唔想去讀書又要幾年學費同放棄現時份工? 呢個加拿大永居簽證計劃可能最啱你。\r\n\r\n加拿大創業簽證Start-Up Visa （SUV）：\r\n1) 需時約一至兩年便可一步到位直接獲得加拿大永居身份\r\n2) 無需創業經驗或自己創業，祇需以投資者身份加入香港創業團隊\r\n3) 極低資產要求，無需解釋財產來源\r\n4) 無居住地區限制（除魁省外），可選擇定居多倫多或溫哥華\r\n5) 無論創業項目成功與否，申請人的永居身份都不會被取消\r\n6) 低入場門檻，祇需英文IELTS 5分，無學歷及資歷要求\r\n7) 有快慢移加時間選擇，可申請Work Permit提早去，或PR批出後再等一兩年才移居即由現在計起最遲3至5年後才需去定居\r\n\r\n本公司之SUV計劃可能是全城最低價，祇要幾十萬港幣就可一步到位成為加拿大永久居民。投資創業+移民二合一，本公司科創項目獲得過本地及海外資助，絕對可信可靠。\r\n\r\n聯絡我們:\r\n電話/Whatsapp: (852)54867893\r\nEmail: admin@wealthskey.com',	'4cb61d5bd35cc1fad8e40b8c510d61d7.jpg',	'',	0,	1,	0,	'2024-04-09 19:00:58',	1,	'2024-06-11 17:21:37',	0,	NULL),
(2,	1,	1,	2,	1,	NULL,	'【#BF社會熱話】八大逾2600名學生退學 創18年新高 理大518人佔最多\r\n大學教育資助委員會公布最新統計數據，八間資助大學的退學人數創新高。在2020至2021學年，連同副學位、學士學位和研究院修課課程的學生在內，有2,643人退學，較對上學年增加約482人，升逾22.3%。若以相當於全日制學生人數定義計算，則是教資會有紀錄以來，即近18年的新高。有升學顧問認為，移民潮是退學率創新高主因。 \r\n八大退學學生之中，最多來自理工大學，共有518人，而香港大學、中文大學及城市大學均有超過400人退學。若以升幅計算，則以浸會大學最高，按年升逾37%，有222人。科技大學亦有270人退學，較上學年上升約30%。\r\n同時，退學學生又以學士課程佔最多，有2,255人，較2019學年的1,816人上升近25%，而副學位課程有324人退學。另外，八大學士課程的人數上升有所放緩。該學年有87,300名學士學生，較前學年上升只有不足500人。\r\n學友社升學顧問吳寶城認為，移民潮是去年退學數字創新高的主因。他指出，過往一兩年的中、小學退學率甚高，相信亦有不少大學生跟隨家人移民外國而退學。同時在疫情影響下，大學需要改為網上授課，他認為學生在網課期間遇上困難亦難以尋求協助，難免令學生對學習意興闌珊而退學。吳寶城又提到，部分學生入讀的科目並非原先的心儀科目，或會因成績不理想而轉校。\r\n《星島日報》引述各院校回應，指退學原因因人而異。港大指出，每年均有少數本地及非本地生因各種原因中止學業，包括學業成績不理想等。同時又表示，退學數字每年或有升跌，與其他大學相若。而理大亦指，每年均有學生以不同原因退學，同指上學年本地生退學情況與往年相若，反之非本地生退學人數稍有增加。\r\nText by BusinessFocus Editorial\r\n—————————————————\r\n【TapNow玩樂著數優惠】\r\n歎創新口味雞翼 外賣自取$78起\r\n包松露醬薯條及汽水👉🏻 https://bit.ly/32rzRV3\r\n銅鑼灣日式燒肉放題 $148起\r\n任食和牛 免費任飲日本麥啤清酒👉🏻 https://bit.ly/3nO7U1a\r\n—————————————————\r\n隨時接收最新投資創富消息 BusinessFocus App\r\n立即下載：https://bit.ly/BFHK-App\r\n—————————————————\r\n了解更多最快最新的財經、商業及創科資訊，請追蹤\r\nInstagram： www.instagram.com/businessfocus.io/\r\n—————————————————\r\n追蹤 MarketFocus 看更多詳盡財經及投資分析\r\nFB：https://www.facebook.com/marketfocus.hk\r\n—————————————————\r\n加入我們 全港最Top人氣商業財經社交媒體\r\nLinkedIn：https://bit.ly/3agkkHW\r\n—————————————————\r\n時刻接收市場最新資訊，請追蹤Telegram頻道：\r\nt.me/businessfocusofficial\r\n—————————————————\r\n請於本專頁cover photo下方，按『Following』按鈕然後選擇『See First』\r\n—————————————————\r\n若有任何商業、財經及科技資訊的新聞稿，歡迎\r\nInbox或電郵至info@businessfocus.io！\r\n廣告合作請電郵至sales@businessfocus.io\r\n—————————————————\r\n如果你對初創、商業及科技界有所見解，敬請投稿\r\n至info@businessfocus.io\r\n訂閱BusinessFocus YouTube頻道：\r\nwww.youtube.com/channel/UCzZszEpbE87Mfh-q7D472BA\r\n歡迎&quot;Join&quot; BF討論區暢談財經、商業及創科話題：BusinessFocus.io 討論區',	'445e986e5a7b299c9fe479cdb66fa9c9.jpg',	'',	0,	0,	0,	'2024-04-09 19:01:59',	0,	'2024-04-09 19:01:59',	1,	'2024-06-05 20:06:35'),
