INSERT INTO `app_page` (`uid`, `parent_id`, `id`, `title`, `content`, `meta_title`, `meta_description`, `meta_image`, `utoken`, `disabled`, `level`, `lang`, `seq`, `status`, `created_by`, `created_at`, `updated_by`, `updated_at`, `deleted_by`, `deleted_at`) VALUES
(1,	0,	1,	'Home',	'',	'',	'',	'',	'e64120ba4a8c1437ab79e6289cd1817f',	0,	1,	1,	10,	1,	1,	'2024-02-07 12:26:11',	1,	'2024-07-18 14:14:23',	0,	NULL),
(2,	0,	1,	'主頁',	'',	'',	'',	'',	'e64120ba4a8c1437ab79e6289cd1817f',	0,	1,	2,	10,	1,	1,	'2024-02-07 12:26:11',	1,	'2024-07-18 14:14:23',	0,	NULL),
(3,	0,	1,	'主页',	'',	'',	'',	'',	'e64120ba4a8c1437ab79e6289cd1817f',	0,	1,	3,	10,	1,	1,	'2024-02-07 12:26:11',	1,	'2024-07-18 14:14:23',	0,	NULL),
(4,	0,	2,	'About Us',	'&lt;p&gt;&lt;strong&gt;AI-mmi&amp;nbsp;&lt;/strong&gt;is a platform and on-line community of the migrants, for the migrants, and by the migrants. This is a one-stop-shop for all information related to pre and post migration to another country. If you are considering moving to a new country, you have the options of getting your migration advisory and application services by our AI agent here or contacting one of our registered migration agents. If you are a migration agent, you may publish migration related news or events here and access to all the subscribers and users. If you are a service provider, you will also have the opportunity to promote your services here for any pre or post migration supports.&lt;/p&gt;',	'',	'',	'',	'89cbcd7fb74756d03cab3869e55b2cfb',	0,	1,	1,	9,	1,	1,	'2024-02-07 12:26:30',	1,	'2024-07-18 14:14:23',	0,	NULL),
(5,	0,	2,	'關於我們',	'&lt;p&gt;&lt;strong&gt;AI-mmi &lt;/strong&gt;是一站式的移民資訊、服務與社區平台，為有計劃移民、即將移民和已經移民的朋友提供實用資料及相關服務。如果你是打算移民，可以使用平台的AI顧問或聯絡在我們平台登記的移民顧問協助你的移民申請。如果你是移民中介，可以直接在平台上發佈實用資訊及活動介紹，為平台的用戶提供服務。如果你是服務提供者，你可以透過我們的平台推廣你的服務。&lt;/p&gt;',	'',	'',	'',	'89cbcd7fb74756d03cab3869e55b2cfb',	0,	1,	2,	9,	1,	1,	'2024-02-07 12:26:30',	1,	'2024-07-18 14:14:23',	0,	NULL),
(6,	0,	2,	'关于我们',	'&lt;p&gt;AI-mmi 是一站式的移民资讯、服务与社区平台，为有计划移民、即将移民和已经移民的朋友提供实用资料及相关服务。如果你是打算移民，可以使用平台的AI顾问或联络在我们平台登记的移民顾问协助你的移民申请。如果你是移民中介，可以直接在平台上发布实用资讯及活动介绍，为平台的用户提供服务。如果你是服务提供者，你可以透过我们的平台推广你的服务。&lt;/p&gt;',	'',	'',	'',	'89cbcd7fb74756d03cab3869e55b2cfb',	0,	1,	3,	9,	1,	1,	'2024-02-07 12:26:30',	1,	'2024-07-18 14:14:23',	0,	NULL),
(7,	0,	4,	'Faqs',	'',	'',	'',	'',	'05ce7983b6eb9178fb226de14837c5c3',	0,	1,	1,	7,	1,	1,	'2024-02-07 12:27:08',	1,	'2024-07-18 14:14:23',	0,	NULL),
(8,	0,	4,	'常見問題',	'',	'',	'',	'',	'05ce7983b6eb9178fb226de14837c5c3',	0,	1,	2,	7,	1,	1,	'2024-02-07 12:27:08',	1,	'2024-07-18 14:14:23',	0,	NULL),
