INSERT INTO `app_plan_visa_submission` (`uid`, `parent_id`, `id`, `title`, `brief`, `content`, `price`, `valid_days`, `meta_title`, `meta_description`, `meta_image`, `utoken`, `disabled`, `level`, `lang`, `seq`, `status`, `created_by`, `created_at`, `updated_by`, `updated_at`, `deleted_by`, `deleted_at`) VALUES
(1,	0,	1,	'AI mode',	'Visa submission DIY with the support of AI (AI-mmi)',	'&lt;ul&gt;\r\n&lt;li&gt;Unlimited access to AI-mmi for visa related questions&lt;/li&gt;\r\n&lt;li&gt;Visa related document validation by AI-mmi&lt;/li&gt;\r\n&lt;li&gt;Profile write-up recommendation by AI-mmi&lt;/li&gt;\r\n&lt;li&gt;Visa application form filling by AI-mmi (limited forms on limited via classes at this stage)&lt;/li&gt;\r\n&lt;li&gt;Duration of support: 3 months&lt;/li&gt;\r\n&lt;/ul&gt;',	299,	90,	NULL,	NULL,	NULL,	'9acf05b87094f00d847dc92261e22c9a',	0,	1,	1,	2,	1,	1,	'2024-02-01 13:05:49',	1,	'2024-06-09 11:12:13',	0,	NULL),
(2,	0,	2,	'Hybrid mode AI+human',	'Visa submission DIY with the support of AI (AI-mmi) &amp; one final review by a professional migration agent',	'&lt;ul&gt;\r\n&lt;li&gt;Unlimited access to AI-mmi for visa related questions&lt;/li&gt;\r\n&lt;li&gt;Visa related document validation by AI-mmi&lt;/li&gt;\r\n&lt;li&gt;Profile write-up recommendation by AI-mmi&lt;/li&gt;\r\n&lt;li&gt;Visa application form filling by AI-mmi (limited forms on limited via classes at this stage)&lt;/li&gt;\r\n&lt;li&gt;A human and professional migration agent served as your gate keeper at the final stage before submission. One final review on the application by a qualified migration agent (up to 3 hours)&lt;/li&gt;\r\n&lt;li&gt;Duration of support: 3 months&lt;/li&gt;\r\n&lt;/ul&gt;',	1999,	90,	NULL,	NULL,	NULL,	'7758e0549b9e68f9d7383b4e919b3987',	0,	1,	1,	1,	1,	1,	'2024-02-01 13:07:07',	1,	'2024-06-09 11:14:04',	0,	NULL),
(3,	0,	1,	'人工智能模式',	'AI支援DIY簽證提交（AI-mmi）',	'&lt;ul&gt;\r\n&lt;li&gt;無限制存取 AI-mmi 解決簽證相關問題&lt;/li&gt;\r\n&lt;li&gt;AI-mmi 驗證簽證相關文件&lt;/li&gt;\r\n&lt;li&gt;AI-mmi 推薦的個人資料撰寫&lt;/li&gt;\r\n&lt;li&gt;由AI-mmi填寫簽證申請表（現階段有限的課程中的有限表格）&lt;/li&gt;\r\n&lt;li&gt;支持期限：3 個月&lt;/li&gt;\r\n&lt;/ul&gt;',	299,	90,	NULL,	NULL,	NULL,	'9acf05b87094f00d847dc92261e22c9a',	0,	1,	2,	2,	1,	1,	'2024-02-05 11:06:48',	1,	'2024-06-09 11:12:13',	0,	NULL),
(4,	0,	1,	'人工智能模式',	'AI支援DIY签证提交（AI-mmi）',	'&lt;ul&gt;\r\n&lt;li&gt;无限制存取 AI-mmi 解决签证相关问题&lt;/li&gt;\r\n&lt;li&gt;AI-mmi 验证签证相关文件&lt;/li&gt;\r\n&lt;li&gt;AI-mmi 推荐的个人资料撰写&lt;/li&gt;\r\n&lt;li&gt;由AI-mmi填写签证申请表（现阶段有限的课程中的有限表格）&lt;/li&gt;\r\n&lt;li&gt;支持期限：3 个月&lt;/li&gt;\r\n&lt;/ul&gt;',	299,	90,	NULL,	NULL,	NULL,	'9acf05b87094f00d847dc92261e22c9a',	0,	1,	3,	2,	1,	1,	'2024-02-05 11:06:48',	1,	'2024-06-09 11:12:13',	0,	NULL),
(5,	0,	2,	'AI+移民顧問模式',	'在人工智能（AI-mmi）的支持下DIY提交簽證並由專業移民顧問在提交前進行一次最終審核',	'&lt;ul&gt;\r\n&lt;li&gt;無限制存取 AI-mmi 解決簽證相關問題&lt;/li&gt;\r\n&lt;li&gt;AI-mmi 驗證簽證相關文件&lt;/li&gt;\r\n&lt;li&gt;AI-mmi 推薦的個人資料撰寫&lt;/li&gt;\r\n&lt;li&gt;由AI-mmi填寫簽證申請表（現階段有限的課程中的有限表格）&lt;/li&gt;\r\n&lt;li&gt;在提交前的最後階段，專業的移民代理將擔任您的把關人。 由合格的移民代理對申請進行一次最終審核（最多 3 小時）&lt;/li&gt;\r\n&lt;li&gt;支持期限：3 個月&lt;/li&gt;\r\n&lt;/ul&gt;',	1999,	90,	NULL,	NULL,	NULL,	'7758e0549b9e68f9d7383b4e919b3987',	0,	1,	2,	1,	1,	1,	'2024-02-05 11:07:24',	1,	'2024-06-09 11:14:04',	0,	NULL),
(6,	0,	2,	'AI+移民顾问模式',	'在人工智能（AI-mmi）的支持下DIY提交签证并由专业移民顾问在提交前进行一次最终审核',	'&lt;ul&gt;\r\n&lt;li&gt;无限制存取 AI-mmi 解决签证相关问题&lt;/li&gt;\r\n&lt;li&gt;AI-mmi 验证签证相关文件&lt;/li&gt;\r\n&lt;li&gt;AI-mmi 推荐的个人资料撰写&lt;/li&gt;\r\n&lt;li&gt;由AI-mmi填写签证申请表（现阶段有限的课程中的有限表格）&lt;/li&gt;\r\n&lt;li&gt;在提交前的最后阶段，专业的移民代理将担任您的把关人。 由合格的移民代理对申请进行一次最终审核（最多 3 小时）&lt;/li&gt;\r\n&lt;li&gt;支持期限：3 个月&lt;/li&gt;\r\n&lt;/ul&gt;',	1999,	90,	NULL,	NULL,	NULL,	'7758e0549b9e68f9d7383b4e919b3987',	0,	1,	3,	1,	1,	1,	'2024-02-05 11:07:24',	1,	'2024-06-09 11:14:04',	0,	NULL);
