(10,	1,	4,	0,	'Business 188a',	'188 Business Innovation &amp; Investment (Provisional) – Investor Stream',	'&lt;ul&gt;\r\n&lt;li&gt;​​​​​​​​​​​​​​​​​​​​​​​​​​​​​​​​​​​​​​​​​Extend your stay for up to 2 more years. This means you can stay in Australia for a total of 6 years from the date of grant of your Subclass 188 visa in the Business Innovation stream.&lt;/li&gt;\r\n&lt;li&gt;You can only have held 1 Business Innovation and Investment (Provisional) visa (subclass 188).&lt;/li&gt;\r\n&lt;li&gt;You must hold a Subclass 188 visa in the Business Innovation stream.&amp;nbsp;&lt;/li&gt;\r\n&lt;li&gt;You must have held your Subclass 188 visa in the Business Innovation stream for at least 3 years.&amp;nbsp;&lt;/li&gt;\r\n&lt;li&gt;You must be nominated by an Australian State or Territory government agency.&amp;nbsp;&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'8931c2b74c492804d7b1939dd7f4944d',	0,	2,	1,	2,	0,	1,	'2024-02-16 17:01:51',	1,	'2024-02-16 17:02:39',	1,	'2024-06-11 15:55:11'),
(11,	1,	4,	0,	'商務188',	'188 商業創新與投資（暫定）- 投資者類別',	'&lt;p&gt;延長您的逗留期限最多2年。 這意味著自商業創新類別 188 子類簽證授予之日起，您可以在澳洲總共停留 6 年。&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;您只能持有 1 個商業創新和投資（臨時）簽證（子類 188）。&lt;/li&gt;\r\n&lt;li&gt;您必須持有商業創新類別的 188 子類簽證。&lt;/li&gt;\r\n&lt;li&gt;您必須持有商業創新類別的 188 子類簽證至少 3 年。&lt;/li&gt;\r\n&lt;li&gt;您必須由澳洲州或領地政府機構提名。&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'8931c2b74c492804d7b1939dd7f4944d',	0,	2,	2,	2,	0,	1,	'2024-02-16 17:01:51',	1,	'2024-02-16 17:02:39',	1,	'2024-06-11 15:55:11'),
(12,	1,	4,	0,	'商务188',	'188 商业创新与投资（暂定）- 投资者类别',	'&lt;p&gt;延长您的逗留期限最多2年。 这意味着自商业创新类别 188 子类签证授予之日起，您可以在澳洲总共停留 6 年。&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;您只能持有 1 个商业创新和投资（临时）签证（子类 188）。&lt;/li&gt;\r\n&lt;li&gt;您必须持有商业创新类别的 188 子类签证。&lt;/li&gt;\r\n&lt;li&gt;您必须持有商业创新类别的 188 子类签证至少 3 年。&lt;/li&gt;\r\n&lt;li&gt;您必须由澳洲州或领地政府机构提名。&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'8931c2b74c492804d7b1939dd7f4944d',	0,	2,	3,	2,	0,	1,	'2024-02-16 17:01:51',	1,	'2024-02-16 17:02:39',	1,	'2024-06-11 15:55:11'),
