(49,	16,	17,	0,	'EB2 NIW Visa Program',	'EB2 NIW Visa Program',	'&lt;p&gt;EB2 National Interest Waiver (NIW) is a fast-track program for outstanding professionals, researchers or businessmen to obtain a permanent residency of the United States (Green Card).&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;The processing time for the EB2 NIW approval for most countries may take 5-17 months. Green Card processing time varies depending on the applicant&amp;rsquo;s country of birth. Countries that have higher immigration populations in the US may take longer (e.g., applicants from China may take 3-4 years and applicants from India may take 7-8 years to wait for the availability of the Green Card).&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;Visa requirements:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;a master&#039;s degree or a bachelor&#039;s degree with a minimum of 5 years of experience&lt;/li&gt;\r\n&lt;li&gt;have exceptional ability in your field&lt;/li&gt;\r\n&lt;li&gt;meet the National Interest Waiver requirements such as the ability to create values to US&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'b15b8a8200953e4de6d0ae97b69bd79d',	0,	2,	1,	1,	1,	1,	'2024-07-12 13:53:15',	1,	'2024-07-12 13:53:15',	0,	NULL),
(50,	16,	17,	0,	'EB2 NIW簽證項目',	'EB2 NIW簽證項目',	'&lt;p&gt;EB2 NIW計劃是一項為傑出專業人士、研究人員或商人提供快速取得美國永久居民身分（綠卡）的計劃。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;大多數國家的EB2 NIW批准處理時間可能需要5-17個月。綠卡處理時間則根據申請人的出生國家而有所不同。在美國移民人口較多的國家，處理時間可能會更長（例如，來自中國的申請人可能需要3-4年，來自印度的申請人可能需要7-8年等待綠卡）。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;申請要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;擁有碩士學位或學士學位，並有至少5年工作經驗&lt;/li&gt;\r\n&lt;li&gt;在自己的領域有卓越才能&lt;/li&gt;\r\n&lt;li&gt;符合國家利益豁免的要求，如能為美國創造價值&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'b15b8a8200953e4de6d0ae97b69bd79d',	0,	2,	2,	1,	1,	1,	'2024-07-12 13:53:15',	1,	'2024-07-12 13:53:15',	0,	NULL),
(51,	16,	17,	0,	'EB2 NIW 签证项目',	'EB2 NIW 签证项目',	'&lt;p&gt;EB2 NIW计划是一项为杰出专业人士、研究人员或商人提供快速取得美国永久居民身分（绿卡）的计划。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;大多数国家的EB2 NIW批准处理时间可能需要5-17个月。绿卡处理时间则根据申请人的出生国家而有所不同。在美国移民人口较多的国家，处理时间可能会更长（例如，来自中国的申请人可能需要3-4年，来自印度的申请人可能需要7-8年等待绿卡）。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;申请要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;拥有硕士学位或学士学位，并有至少5年工作经验&lt;/li&gt;\r\n&lt;li&gt;在自己的领域有卓越才能&lt;/li&gt;\r\n&lt;li&gt;符合国家利益豁免的要求，如能为美国创造价值&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'b15b8a8200953e4de6d0ae97b69bd79d',	0,	2,	3,	1,	1,	1,	'2024-07-12 13:53:15',	1,	'2024-07-12 13:53:15',	0,	NULL),
(52,	16,	18,	0,	'EB5 Investor Visa Program',	'EB5 Investor Visa Program',	'&lt;p&gt;EB-5 Immigrant Investor Program (EB-5 visa) allows a foreign investor, their spouse and unmarried children under the age of 21 to get a green card by investing US$800K (Regional Center, or RC) or US$1.05 million (non RC) in a new US business or development project.&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;Visa requirements:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;invest a minimum of US$800K to an eligible project that creates at least 10 new full-time jobs in US&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'5606167eacdc56afd4a1644cd129c007',	0,	2,	1,	2,	0,	1,	'2024-07-12 13:56:44',	1,	'2024-07-12 13:57:08',	1,	'2024-07-12 13:57:39'),
(53,	16,	18,	0,	'EB5 投資移民計劃',	'EB5 投資移民計劃',	'&lt;p&gt;EB-5 移民投資者計劃（EB-5簽證）允許外國投資者及其配偶和21歲以下未婚子女，通過在美國投資80萬美元（區域中心項目）或105萬美元（非區域中心項目）來獲得綠卡。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;申請要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;投資至少80萬美元到一個合格的項目，該項目須在美國創造至少10個全職就業崗位&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'5606167eacdc56afd4a1644cd129c007',	0,	2,	2,	2,	0,	1,	'2024-07-12 13:56:44',	1,	'2024-07-12 13:57:08',	1,	'2024-07-12 13:57:39'),
(54,	16,	18,	0,	'EB5 投资移民计划',	'EB5 投资移民计划',	'&lt;p&gt;EB-5 移民投资者计划（EB-5签证）允许外国投资者及其配偶和21岁以下未婚子女，通过在美国投资80万美元（区域中心项目）或105万美元（非区域中心项目）来获得绿卡。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;申请要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;投资至少80万美元到一个合格的项目，该项目须在美国创造至少10个全职就业岗位&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'5606167eacdc56afd4a1644cd129c007',	0,	2,	3,	2,	0,	1,	'2024-07-12 13:56:44',	1,	'2024-07-12 13:57:08',	1,	'2024-07-12 13:57:39'),
(55,	0,	19,	2,	'EB5 Investor Visa Program',	NULL,	NULL,	NULL,	NULL,	NULL,	'e55d236c8a2f1c7c71a06392ac435336',	0,	1,	1,	8,	1,	1,	'2024-07-12 13:58:55',	1,	'2024-07-12 13:58:55',	0,	NULL),
