(58,	19,	20,	0,	'EB5 Investor Visa Program',	'EB5 Investor Visa Program',	'&lt;p&gt;EB-5 Immigrant Investor Program (EB-5 visa) allows a foreign investor, their spouse and unmarried children under the age of 21 to get a green card by investing US$800K (Regional Center, or RC) or US$1.05 million (non RC) in a new US business or development project.&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;Visa requirements:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;invest a minimum of US$800K to an eligible project that creates at least 10 new full-time jobs in US&lt;/li&gt;\r\n&lt;/ul&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;',	'',	'',	'',	'18d109368432cac6187ae41b9f58d19f',	0,	2,	1,	1,	1,	1,	'2024-07-12 14:01:01',	1,	'2024-07-12 14:01:01',	0,	NULL),
(59,	19,	20,	0,	'EB5 投資移民計劃',	'EB5 投資移民計劃',	'&lt;p&gt;EB-5 移民投資者計劃（EB-5 簽證）允許外國投資者及其配偶和21歲以下未婚子女，通過在美國投資80萬美元（區域中心項目）或105萬美元（非區域中心項目）來獲得綠卡。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;申請要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;投資至少80萬美元到一個合格的項目，該項目須在美國創造至少10個全職就業崗位&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'18d109368432cac6187ae41b9f58d19f',	0,	2,	2,	1,	1,	1,	'2024-07-12 14:01:01',	1,	'2024-07-12 14:01:01',	0,	NULL),
(60,	19,	20,	0,	'EB5 投资移民计划',	'EB5 投资移民计划',	'&lt;p&gt;EB-5 移民投资者计划（EB-5 签证）允许外国投资者及其配偶和21岁以下未婚子女，通过在美国投资80万美元（区域中心项目）或105万美元（非区域中心项目）来获得绿卡。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;申请要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;投资至少80万美元到一个合格的项目，该项目须在美国创造至少10个全职就业岗位&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'18d109368432cac6187ae41b9f58d19f',	0,	2,	3,	1,	1,	1,	'2024-07-12 14:01:01',	1,	'2024-07-12 14:01:01',	0,	NULL),
