(64,	21,	22,	0,	'Entrepreneur Immigration',	'Entrepreneur Immigration',	'&lt;p&gt;The Entrepreneur Immigration is an economic immigration program for qualified candidates who want to launch start-up enterprises and innovative businesses in the selective provinces of Canada.&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;Requirements:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;have completed a post-secondary qualification&lt;/li&gt;\r\n&lt;li&gt;meet the language skill in either English or French (e.g. IELTS 4 or 5)&lt;/li&gt;\r\n&lt;li&gt;start an eligible business in the designated areas of the selective province&lt;/li&gt;\r\n&lt;li&gt;invest from C$50K to C$200K in your own business depending on the location and program&lt;/li&gt;\r\n&lt;li&gt;actively own and operate the business for at least 12 months with a work permit granted&lt;/li&gt;\r\n&lt;li&gt;apply for permanent residency after meeting the project report is approved&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'adfb1405a18140c0bc09549ef0483577',	0,	2,	1,	1,	1,	1,	'2024-07-15 02:06:03',	1,	'2024-07-15 02:06:03',	0,	NULL),
(65,	21,	22,	0,	'企業家移民',	'企業家移民',	'&lt;p&gt;企業家是一項面向有意在加拿大特定省份創辦初創企業和創新型企業的合格候選人的經濟移民計劃。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;要求:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;已完成大學或以上學歷&lt;/li&gt;\r\n&lt;li&gt;達到英語或法語的語言技能要求(如IELTS 4或5分)&lt;/li&gt;\r\n&lt;li&gt;在指定省份的合適地區開辦合格的企業&lt;/li&gt;\r\n&lt;li&gt;根據地點和計劃投資5萬加元到20萬加元在自己的企業&lt;/li&gt;\r\n&lt;li&gt;在獲得工作許可的情況下,積極擁有並經營企業至少12個月&lt;/li&gt;\r\n&lt;li&gt;在項目報告獲批准後申請永久居民身份&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'adfb1405a18140c0bc09549ef0483577',	0,	2,	2,	1,	1,	1,	'2024-07-15 02:06:03',	1,	'2024-07-15 02:06:03',	0,	NULL),
(66,	21,	22,	0,	'企业家移民',	'企业家移民',	'&lt;p&gt;企业家是一项面向有意在加拿大特定省份创办初创企业和创新型企业的合格候选人的经济移民计划。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;要求:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;已完成大学或以上学歷&lt;/li&gt;\r\n&lt;li&gt;达到英语或法语的语言技能要求(如IELTS 4或5分)&lt;/li&gt;\r\n&lt;li&gt;在指定省份的合适地区开办合格的企业&lt;/li&gt;\r\n&lt;li&gt;根据地点和计划投资5万加元到20万加元在自己的企业&lt;/li&gt;\r\n&lt;li&gt;在获得工作许可的情况下,积极拥有并经营企业至少12个月&lt;/li&gt;\r\n&lt;li&gt;在项目报告获批准后申请永久居民身份&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'adfb1405a18140c0bc09549ef0483577',	0,	2,	3,	1,	1,	1,	'2024-07-15 02:06:03',	1,	'2024-07-15 02:06:03',	0,	NULL),
(67,	0,	23,	3,	'Skilled Migration Program',	NULL,	NULL,	NULL,	NULL,	NULL,	'dd1f65ffade86c58c6045bf7ab395969',	0,	1,	1,	10,	1,	1,	'2024-07-15 02:09:15',	1,	'2024-07-15 02:09:15',	0,	NULL),
