(82,	27,	28,	0,	'Temporary Skill Shortage Subclass 482 Visa',	'Temporary Skill Shortage Subclass 482 Visa',	'&lt;p&gt;This is a temporary residency visa allowing Australian businesses to nominate overseas workers to fulfill skills shortages in their business. It permits the visa holders to stay up to 2, 4 or 5 years depending on the visa streams. Applicant must meet the work experience, occupation, English, health and character requirements.&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;',	'',	'',	'',	'bbf2e509d29017a68f2f77c13ad1a2de',	0,	2,	1,	1,	1,	1,	'2024-07-15 02:30:47',	1,	'2024-07-15 02:30:47',	0,	NULL),
(83,	27,	28,	0,	'482雇主擔保簽證',	'482雇主擔保簽證',	'&lt;p&gt;這允許澳洲企業提名海外工人填補短期短缺職位。這是一種臨時居留簽證，允許簽證持有人根據簽證類別停留 2、4 或 5 年。申請人必須滿足工作經驗、職業、英語、健康和品格要求。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;',	'',	'',	'',	'bbf2e509d29017a68f2f77c13ad1a2de',	0,	2,	2,	1,	1,	1,	'2024-07-15 02:30:47',	1,	'2024-07-15 02:30:47',	0,	NULL),
(84,	27,	28,	0,	'482雇主担保签证',	'482雇主担保签证',	'&lt;p&gt;这允许澳洲企业提名海外工人填补短期短缺职位。这是一种临时居留签证，允许签证持有人根据签证类别停留 2、4 或 5 年。申请人必须满足工作经验、职业、英语、健康和品格要求。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;',	'',	'',	'',	'bbf2e509d29017a68f2f77c13ad1a2de',	0,	2,	3,	1,	1,	1,	'2024-07-15 02:30:47',	1,	'2024-07-15 02:30:47',	0,	NULL),
(85,	0,	29,	4,	'Studying and Training Visas',	NULL,	NULL,	NULL,	NULL,	NULL,	'a4bd5125a6224c5e6afbdabc7987307c',	0,	1,	1,	12,	1,	1,	'2024-07-19 13:03:11',	1,	'2024-07-19 13:03:11',	0,	NULL),
(86,	0,	29,	4,	'留學及培訓簽證',	NULL,	NULL,	NULL,	NULL,	NULL,	'a4bd5125a6224c5e6afbdabc7987307c',	0,	1,	2,	12,	1,	1,	'2024-07-19 13:03:11',	1,	'2024-07-19 13:03:11',	0,	NULL),
(87,	0,	29,	4,	'留学及培训签证',	NULL,	NULL,	NULL,	NULL,	NULL,	'a4bd5125a6224c5e6afbdabc7987307c',	0,	1,	3,	12,	1,	1,	'2024-07-19 13:03:11',	1,	'2024-07-19 13:03:11',	0,	NULL),
(88,	29,	30,	0,	'Subclass 500 Student Visa',	'Subclass 500 Student Visa',	'&lt;p&gt;This is a temporary visa to study up to 5 years. The type of course and its length will determine the length of stay. Primary school children enrolled in years 1-4 will generally only be granted a student visa for a maximum period of 3 years. This visa permits you to participate in an eligible course of study in Australia, travel in and out of the country, and work up to 48 hours a fortnight when your course of study or training is in session (students studying a masters by research or doctoral degree, and their families, have no work limit).&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;Visa requirements:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;apply online in or outside Australia&lt;/li&gt;\r\n&lt;li&gt;be enrolled in a full-time course registered on the Commonwealth Register of Institutions and courses for Overseas Students (CRICOS) and provide a Confirmation of Enrollment (CoE)&lt;/li&gt;\r\n&lt;li&gt;be at least 6 years old&lt;/li&gt;\r\n&lt;li&gt;provide proof of a welfare arrangement, if you are under 18&lt;/li&gt;\r\n&lt;li&gt;meet English language requirements (e.g. IELTS)&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'2e1bae70a560670fdb55d77477975978',	0,	2,	1,	1,	1,	1,	'2024-07-19 13:05:37',	1,	'2024-07-19 13:05:37',	0,	NULL),
(89,	29,	30,	0,	'500學生簽證',	'500學生簽證',	'&lt;p&gt;這是一個為期最長5年的臨時簽證。課程類型和時長將決定您的停留時間。就讀1-4年級的小學生通常只能獲得最長3年的學生簽證。此簽證允許您參加澳洲的合格課程學習，進出澳洲，並在課程學習或培訓期間每週工作最多48小時（攻讀碩士研究生或博士學位的學生及其家人沒有工作時間限制）。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;簽證要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;在澳洲境內或境外線上申請&lt;/li&gt;\r\n&lt;li&gt;註冊於澳洲海外學生機構及課程註冊名單 (CRICOS) 的全日制課程，並提供入學確認書 (CoE)&lt;/li&gt;\r\n&lt;li&gt;年齡至少 6 歲&lt;/li&gt;\r\n&lt;li&gt;如果您未滿 18 歲，請提供福利安排證明&lt;/li&gt;\r\n&lt;li&gt;滿足英語語言要求（例如雅思）&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'2e1bae70a560670fdb55d77477975978',	0,	2,	2,	1,	1,	1,	'2024-07-19 13:05:37',	1,	'2024-07-19 13:05:37',	0,	NULL),
(90,	29,	30,	0,	'500学生签证',	'500学生签证',	'&lt;p&gt;这是一个为期最长5年的临时签证。课程类型和时长将决定您的停留时间。就读1-4年级的小学生通常只能获得最长3年的学生签证。此签证允许您参加澳洲的合格课程学习，进出澳洲，并在课程学习或培训期间每週工作最多48小时（攻读硕士研究生或博士学位的学生及其家人没有工作时间限制）。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;签证要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;在澳洲境内或境外线上申请&lt;/li&gt;\r\n&lt;li&gt;註册于澳洲海外学生机构及课程註册名单 (CRICOS) 的全日制课程，并提供入学确认书 (CoE)&lt;/li&gt;\r\n&lt;li&gt;年龄至少 6 岁&lt;/li&gt;\r\n&lt;li&gt;如果您未满 18 岁，请提供福利安排证明&lt;/li&gt;\r\n&lt;li&gt;满足英语语言要求（例如雅思）&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'2e1bae70a560670fdb55d77477975978',	0,	2,	3,	1,	1,	1,	'2024-07-19 13:05:37',	1,	'2024-07-19 13:05:37',	0,	NULL),
(91,	11,	31,	0,	'Subclass 485 Temporary Graduate Visa',	'Subclass 485 Temporary Graduate Visa',	'&lt;p&gt;This is a temporary visa that allows international students to live, study and work after you have finished your studies.&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;Visa requirements:&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;be aged 35 years or under when you apply (applicants under 50 years of age are still eligible if they hold a Hong Kong or British National Overseas passport)&lt;/li&gt;\r\n&lt;li&gt;hold an eligible visa&lt;/li&gt;\r\n&lt;li&gt;have held a Student visa in the last 6 months&lt;/li&gt;\r\n&lt;li&gt;have a recent qualification in a CRICOS-registered course&lt;/li&gt;\r\n&lt;li&gt;apply for your eligible stream (it is not possible to change streams after you apply)&lt;/li&gt;\r\n&lt;li&gt;attach required evidence when you apply&lt;/li&gt;\r\n&lt;li&gt;English proficiency level (e.g. scoring 6.5 for IELTS)&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'acbb81b622645b0f18a80a60ee14afc1',	0,	2,	1,	4,	1,	1,	'2024-07-19 13:08:56',	1,	'2024-07-19 13:08:56',	0,	NULL),
(92,	11,	31,	0,	'485臨時畢業生簽證',	'485臨時畢業生簽證',	'&lt;p&gt;這是一個臨時簽證，允許國際學生在完成學業後在澳洲生活、學習和工作。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;簽證要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;申請時年齡必須在35歲或以下（如果持有香港或英國國民（海外）護照的申請者50歲以下仍有資格）&lt;/li&gt;\r\n&lt;li&gt;持有符合資格的簽證&lt;/li&gt;\r\n&lt;li&gt;在過去6個月內持有學生簽證&lt;/li&gt;\r\n&lt;li&gt;擁有最近在CRICOS註冊課程中獲得的資格&lt;/li&gt;\r\n&lt;li&gt;申請符合資格的類別（申請後無法更改類別）&lt;/li&gt;\r\n&lt;li&gt;申請時附上所需證據&lt;/li&gt;\r\n&lt;li&gt;英語水平達要求（例如IELTS成績6.5分）&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'acbb81b622645b0f18a80a60ee14afc1',	0,	2,	2,	4,	1,	1,	'2024-07-19 13:08:56',	1,	'2024-07-19 13:08:56',	0,	NULL),
(93,	11,	31,	0,	'485临时毕业生签证',	'485临时毕业生签证',	'&lt;p&gt;这是一个临时签证，允许国际学生在完成学业后在澳洲生活、学习和工作。&lt;/p&gt;\r\n&lt;p&gt;&amp;nbsp;&lt;/p&gt;\r\n&lt;p&gt;&lt;strong&gt;签证要求：&lt;/strong&gt;&lt;/p&gt;\r\n&lt;ul&gt;\r\n&lt;li&gt;申请时年龄必须在35岁或以下（如果持有香港或英国国民（海外）护照的申请者50岁以下仍有资格）&lt;/li&gt;\r\n&lt;li&gt;持有符合资格的签证&lt;/li&gt;\r\n&lt;li&gt;在过去6个月内持有学生签证&lt;/li&gt;\r\n&lt;li&gt;拥有最近在CRICOS註册课程中获得的资格&lt;/li&gt;\r\n&lt;li&gt;申请符合资格的类别（申请后无法更改类别）&lt;/li&gt;\r\n&lt;li&gt;申请时附上所需证据&lt;/li&gt;\r\n&lt;li&gt;英语水平达要求（例如IELTS成绩6.5分）&lt;/li&gt;\r\n&lt;/ul&gt;',	'',	'',	'',	'acbb81b622645b0f18a80a60ee14afc1',	0,	2,	3,	4,	1,	1,	'2024-07-19 13:08:56',	1,	'2024-07-19 13:08:56',	0,	NULL);
